import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3680_家登/20260509/F15_關係人交易與利益輸送風險.md","filePath":"審計報告庫/財務審計/3680_家登/20260509/F15_關係人交易與利益輸送風險.md"}'),l={name:"審計報告庫/財務審計/3680_家登/20260509/F15_關係人交易與利益輸送風險.md"};function o(n,a,s,h,d,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f15-關係人交易與利益輸送風險-財務審計專家報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務審計專家報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務審計專家報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>關係人交易規模與定價公平性分析，是否存在利益輸送或虛增利潤風險。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：經常性關係人交易極低（銷貨 &lt;0.3%、進貨 4%），無異常。但 4.05 億廠房售予關係人技鋼，處分利益 1.25 億，年底款項未收，透明度待提高。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2025 Q4</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>關係人銷貨 1,932 萬（佔營收 0.26%）極低，進貨 1.69 億（佔 4%）正常。重大交易：廠房售予技鋼 4.05 億，處分利益 1.25 億，款項年底未收。背書保證 20.54 億（子公司為主）。資金貸與已全數收回。廠房出售款至年底未清是主要疑點，貢獻 EPS 約 1.04 元（佔全年約 11%）。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、經常性交易評估" tabindex="-1">一、經常性交易評估 <a class="header-anchor" href="#一、經常性交易評估" aria-label="Permalink to &quot;一、經常性交易評估&quot;">​</a></h3><p>銷貨 1,932 萬（佔 0.26%）、進貨 1.69 億（佔 4%），遠低於 5% 關切門檻。進貨對象（垚鋐、寰美、金匯）為半導體關聯企業，具商業實質。租賃年租金 737 萬合理。無利益輸送跡象。</p><h3 id="二、廠房出售予技鋼" tabindex="-1">二、廠房出售予技鋼 <a class="header-anchor" href="#二、廠房出售予技鋼" aria-label="Permalink to &quot;二、廠房出售予技鋼&quot;">​</a></h3><p>價款 4.05 億、處分利益 1.25 億，至年底全額列其他應收款未收回。兩個疑點：①交易對手為實質關係人，定價公平性需鑑價佐證 ②款項完全未收，現金利益尚未實現。若 2026 年順利收回則為一次性現金流入。</p><h3 id="三、背書保證" tabindex="-1">三、背書保證 <a class="header-anchor" href="#三、背書保證" aria-label="Permalink to &quot;三、背書保證&quot;">​</a></h3><p>總額 20.54 億（佔權益 18%），以子公司為主。GUDENG 日本廠 8.34 億最高，反映建設融資擔保。權益 114.1 億 vs 保證總額 20.54 億，覆蓋倍數 5.6x 風險可控。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>4.05 億廠房售予關係人款項未收</strong>，現金利益尚未實現。若買方資金不足或交易生變，可能導致減損。價格公平性存疑。</li><li><strong>背書保證 20.54 億或有負債壓力</strong>：GUDENG（日本廠）尚未獲利、家謙上海持續虧損，若違約家登須代償。</li><li><strong>技鋼應收款佔關係人應收 98% 以上</strong>，不動產過戶後款項遲遲未清，可能隱含買方資金調度問題。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>經常性交易透明且規模小</strong>（銷貨 0.26%、進貨 4%），會計師未列為重大事項。</li><li><strong>資金貸與已全數收回</strong>，集團資金管理有序。</li><li><strong>背書保證有日本新廠等實質資產對應</strong>。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>關係人交易治理中上，唯一需關注廠房出售予技鋼交易的款項收回時程與價格公平性。2026 Q1 財報為確認現金化的關鍵窗口。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>年報：2025_Q4_3680_合併.pdf（第 105-115 頁關係人交易附註）</li><li>原始數據：FinMind TaiwanStockBalanceSheet（關係人應收/應付款項）</li><li>查詢參數：stock_id=3680, end=2025-12-31</li><li>數據查詢日期：2026-05-09</li></ul>',24)])])}const p=e(l,[["render",o]]);export{u as __pageData,p as default};
